namespace LlmWinFormsTemplate;

static class Program
{
    [STAThread]
    static void Main()
    {
        // Global exception handlers → crash.log
        Application.ThreadException += (s, e) => LogCrash("ThreadException", e.Exception);
        AppDomain.CurrentDomain.UnhandledException += (s, e) =>
        {
            if (e.ExceptionObject is Exception ex)
                LogCrash("UnhandledException", ex);
        };
        Application.SetUnhandledExceptionMode(UnhandledExceptionMode.CatchException);

        // Uncomment if using ScottPlot:
        // ScottPlot.Fonts.Default = "Malgun Gothic";

        ApplicationConfiguration.Initialize();
        Application.Run(new Features.Sample.SampleForm());
    }

    /// <summary>
    /// Writes crash info to crash.log with timestamp, source, message, and stack trace.
    /// </summary>
    static void LogCrash(string source, Exception ex)
    {
        try
        {
            var logPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "crash.log");
            var entry = $"""
                [{DateTime.Now:yyyy-MM-dd HH:mm:ss}] Source: {source}
                Message: {ex.Message}
                Stack: {ex.StackTrace}
                ---
                """;
            File.AppendAllText(logPath, entry + Environment.NewLine);
        }
        catch
        {
            // Last resort: ignore logging failure
        }
    }
}

using System.Text.Json;

namespace LlmWinFormsTemplate;

/// <summary>
/// Strongly-typed config loaded from config.json. Add properties as needed.
/// </summary>
public sealed class AppConfig
{
    public string AppName { get; set; } = "LlmWinFormsTemplate";
    public string SerialPort { get; set; } = "COM1";
    public int BaudRate { get; set; } = 9600;
    public string DbPath { get; set; } = "app.db";

    private static readonly JsonSerializerOptions JsonOpts = new()
    {
        PropertyNameCaseInsensitive = true,
        WriteIndented = true
    };

    /// <summary>
    /// Loads config from config.json next to the executable.
    /// Returns default config if file is missing or unreadable.
    /// </summary>
    public static AppConfig Load()
    {
        var path = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "config.json");
        if (!File.Exists(path))
            return new AppConfig();

        try
        {
            var json = File.ReadAllText(path);
            return JsonSerializer.Deserialize<AppConfig>(json, JsonOpts) ?? new AppConfig();
        }
        catch
        {
            return new AppConfig();
        }
    }

    /// <summary>
    /// Saves current config to config.json.
    /// </summary>
    public void Save()
    {
        var path = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "config.json");
        var json = JsonSerializer.Serialize(this, JsonOpts);
        File.WriteAllText(path, json);
    }
}

namespace LlmWinFormsTemplate.Shared.Models;

/// <summary>
/// Common interface for communication devices (serial, TCP, etc.).
/// </summary>
public interface IDevice
{
    bool IsConnected { get; }
    bool Connect();
    void Disconnect();
    void Send(byte[] data);

    /// <summary>Fired when data is received from the device.</summary>
    event EventHandler<byte[]> DataReceived;
}

using System.IO.Ports;
using LlmWinFormsTemplate.Shared.Models;

namespace LlmWinFormsTemplate.Shared.Communication;

/// <summary>
/// Basic serial port wrapper implementing IDevice.
/// </summary>
public sealed class SerialPortHelper : IDevice, IDisposable
{
    private SerialPort? _port;
    private readonly string _portName;
    private readonly int _baudRate;

    public bool IsConnected => _port?.IsOpen == true;
    public event EventHandler<byte[]>? DataReceived;

    public SerialPortHelper(string portName, int baudRate = 9600)
    {
        _portName = portName;
        _baudRate = baudRate;
    }

    public bool Connect()
    {
        try
        {
            _port = new SerialPort(_portName, _baudRate)
            {
                ReadTimeout = 1000,
                WriteTimeout = 1000
            };
            _port.DataReceived += OnPortDataReceived;
            _port.Open();
            return true;
        }
        catch (Exception)
        {
            _port?.Dispose();
            _port = null;
            return false;
        }
    }

    public void Disconnect()
    {
        if (_port == null) return;
        try
        {
            if (_port.IsOpen) _port.Close();
        }
        finally
        {
            _port.DataReceived -= OnPortDataReceived;
            _port.Dispose();
            _port = null;
        }
    }

    public void Send(byte[] data)
    {
        if (_port?.IsOpen != true) return;
        _port.Write(data, 0, data.Length);
    }

    /// <summary>Sends a string with optional line ending.</summary>
    public void SendLine(string text)
    {
        if (_port?.IsOpen != true) return;
        _port.WriteLine(text);
    }

    private void OnPortDataReceived(object sender, SerialDataReceivedEventArgs e)
    {
        try
        {
            if (_port == null || !_port.IsOpen) return;
            var count = _port.BytesToRead;
            if (count <= 0) return;
            var buf = new byte[count];
            _port.Read(buf, 0, count);
            DataReceived?.Invoke(this, buf);
        }
        catch
        {
            // Swallow read errors during disconnect
        }
    }

    public void Dispose() => Disconnect();
}

using Microsoft.Data.Sqlite;

namespace LlmWinFormsTemplate.Shared.Database;

/// <summary>
/// Minimal SQLite helper. Uses Microsoft.Data.Sqlite.
/// </summary>
public sealed class DbHelper : IDisposable
{
    private readonly string _connStr;
    private SqliteConnection? _conn;

    public DbHelper(string dbPath)
    {
        _connStr = $"Data Source={dbPath}";
    }

    /// <summary>Opens connection (creates file if missing).</summary>
    public void Open()
    {
        _conn = new SqliteConnection(_connStr);
        _conn.Open();
    }

    /// <summary>Executes a non-query command (CREATE, INSERT, UPDATE, DELETE).</summary>
    public int Execute(string sql, params (string name, object? value)[] parameters)
    {
        using var cmd = CreateCommand(sql, parameters);
        return cmd.ExecuteNonQuery();
    }

    /// <summary>Reads rows. Caller processes each row via the callback.</summary>
    public void Query(string sql, Action<SqliteDataReader> rowAction,
        params (string name, object? value)[] parameters)
    {
        using var cmd = CreateCommand(sql, parameters);
        using var reader = cmd.ExecuteReader();
        while (reader.Read())
            rowAction(reader);
    }

    /// <summary>Returns a single scalar value.</summary>
    public object? Scalar(string sql, params (string name, object? value)[] parameters)
    {
        using var cmd = CreateCommand(sql, parameters);
        return cmd.ExecuteScalar();
    }

    private SqliteCommand CreateCommand(string sql, (string name, object? value)[] parameters)
    {
        if (_conn == null) throw new InvalidOperationException("Call Open() first.");
        var cmd = _conn.CreateCommand();
        cmd.CommandText = sql;
        foreach (var (name, value) in parameters)
            cmd.Parameters.AddWithValue(name, value ?? DBNull.Value);
        return cmd;
    }

    public void Dispose()
    {
        _conn?.Close();
        _conn?.Dispose();
        _conn = null;
    }
}

namespace LlmWinFormsTemplate.Features.Sample;

/// <summary>
/// Sample form demonstrating feature folder pattern.
/// Replace with your main form or add more features.
/// </summary>
public partial class SampleForm : Form
{
    private readonly SampleService _service;

    public SampleForm()
    {
        InitializeComponent();
        _service = new SampleService();
    }

    private void SampleForm_Load(object sender, EventArgs e)
    {
        Text = _service.Config.AppName;
        lblStatus.Text = "Ready";
    }

    private void BtnTest_Click(object sender, EventArgs e)
    {
        lblStatus.Text = _service.GetStatus();
    }
}

